import datetime

class FairnessMonitor:
    """Weekly fairness metric tracker for production Claude deployments."""

    def __init__(self, db_conn, alert_threshold: float = 0.80):
        self.db = db_conn
        self.threshold = alert_threshold

    def weekly_report(self, deployment_id: str, week_start: datetime.date) -> dict:
        rows = self.db.query("""
            SELECT protected_group, subgroup_value,
                   COUNT(*) AS n,
                   AVG(CASE WHEN outcome = 'positive' THEN 1.0 ELSE 0.0 END) AS rate
            FROM ai_decisions
            WHERE deployment_id = %s
              AND decision_date >= %s AND decision_date < %s + INTERVAL '7 days'
            GROUP BY protected_group, subgroup_value
        """, [deployment_id, week_start, week_start])

        alerts = []
        for group, subrows in _group_by(rows, "protected_group").items():
            max_rate = max(r["rate"] for r in subrows)
            for row in subrows:
                ratio = row["rate"] / max_rate if max_rate > 0 else 1.0
                if ratio < self.threshold:
                    alerts.append({
                        "group": group,
                        "subgroup": row["subgroup_value"],
                        "rate": row["rate"],
                        "max_rate": max_rate,
                        "adverse_impact_ratio": ratio,
                        "n": row["n"],
                    })
        return {"week": str(week_start), "deployment": deployment_id,
                "alerts": alerts, "alert_count": len(alerts)}
